import React from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import { StackScreenProps } from '@react-navigation/stack';
import { AgendamentoStackParamList } from '../../navigation/types';

type Props = StackScreenProps<AgendamentoStackParamList, 'DetalhesMedico'>;

const MedicoDetalhesScreen: React.FC<Props> = ({ route, navigation }) => {
  const { medicoId, amount, pixKey, nomeProfissional } = route.params ?? {};

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Detalhes do Médico</Text>
      <Text style={styles.label}>ID: {medicoId}</Text>
      <Text style={styles.paragraph}>
        Dados do médico serão exibidos aqui (nome, especialidade, local de atendimento, horários disponíveis, avaliações).
      </Text>

      <TouchableOpacity
        style={styles.button}
        onPress={() =>
          navigation.navigate('SelecaoHorario', {
            medicoId: medicoId ?? '',
            amount,
            pixKey,
            nomeProfissional,
          })
        }
      >
        <Text style={styles.buttonText}>Escolher Horário</Text>
      </TouchableOpacity>
    </View>
  );
};

const styles = StyleSheet.create({
  container: { flex: 1, padding: 16, backgroundColor: '#FFF' },
  title: { fontSize: 20, fontWeight: '700', marginTop: 8, marginBottom: 8 },
  label: { fontSize: 14, color: '#666', marginBottom: 6 },
  paragraph: { fontSize: 14, color: '#333', marginBottom: 20 },
  button: { backgroundColor: '#4CAF50', padding: 14, borderRadius: 8, alignItems: 'center' },
  buttonText: { color: '#FFF', fontWeight: '700' },
});

export default MedicoDetalhesScreen;

import React, { useEffect, useState } from 'react';
import {
  View, Text, StyleSheet, ScrollView, TouchableOpacity,
  ActivityIndicator, Image,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { StackScreenProps } from '@react-navigation/stack';
import { Ionicons } from '@expo/vector-icons';
import { AgendamentoStackParamList } from '../../navigation/types';
import uaiMedApi from '../../api/uaiMedApi';

type Props = StackScreenProps<AgendamentoStackParamList, 'DetalhesMedico'>;

interface MedicoPerfil {
  id: string;
  nome: string;
  email: string;
  telefone: string;
  especialidade: string;
  crm: string;
  cidade: string;
  estado: string;
  endereco: string;
  dataFormacao: string;
  pixKey: string | null;
  totalAgendamentos: number;
  totalAvaliacoes: number;
  notaMedia: number | null;
  avaliacoes: { id: string; nota: number; comentario: string | null; paciente: string; data: string }[];
}

const Estrelas: React.FC<{ nota: number }> = ({ nota }) => (
  <View style={{ flexDirection: 'row', gap: 2 }}>
    {[1,2,3,4,5].map(i => (
      <Ionicons key={i} name={i <= nota ? 'star' : 'star-outline'} size={14} color="#FFC107" />
    ))}
  </View>
);

const MedicoDetalhesScreen: React.FC<Props> = ({ route, navigation }) => {
  const { medicoId, pixKey: pixKeyParam, nomeProfissional } = route.params ?? {};
  const [perfil, setPerfil] = useState<MedicoPerfil | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!medicoId) { setLoading(false); return; }
    uaiMedApi.get(`/medicos/${medicoId}`)
      .then(r => setPerfil(r.data))
      .catch(() => setPerfil(null))
      .finally(() => setLoading(false));
  }, [medicoId]);

  const anoFormacao = perfil?.dataFormacao
    ? new Date(perfil.dataFormacao).getFullYear()
    : null;
  const anosExp = anoFormacao ? new Date().getFullYear() - anoFormacao : null;

  const iniciais = perfil?.nome
    ? perfil.nome.split(' ').slice(0,2).map(n => n[0]).join('').toUpperCase()
    : '?';

  const handleAgendar = () =>
    navigation.navigate('SelecaoHorario', {
      medicoId: medicoId ?? '',
      pixKey: perfil?.pixKey ?? pixKeyParam,
      nomeProfissional: perfil?.nome ?? nomeProfissional,
    });

  const handleConversar = async () => {
    if (!medicoId) return;
    try {
      const res = await uaiMedApi.post('/conversas', {
        profissionalId: medicoId,
        titulo: perfil?.nome,
      });
      navigation.getParent<any>()?.navigate('Conversas', {
        screen: 'ConversaDetalhe',
        params: { conversaId: res.data.id, titulo: perfil?.nome, nomeOutro: perfil?.nome },
      });
    } catch { /* navega mesmo assim */ }
  };

  if (loading) {
    return (
      <SafeAreaView style={s.container}>
        <View style={s.centered}><ActivityIndicator size="large" color="#4CAF50" /></View>
      </SafeAreaView>
    );
  }

  if (!perfil) {
    return (
      <SafeAreaView style={s.container}>
        <View style={s.centered}>
          <Ionicons name="alert-circle-outline" size={48} color="#CCC" />
          <Text style={s.erroTxt}>Perfil não encontrado</Text>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={s.container} edges={['bottom']}>
      <ScrollView showsVerticalScrollIndicator={false}>

        {/* ── Hero / Avatar ── */}
        <View style={s.hero}>
          <View style={s.avatarCircle}>
            {perfil.avatar
              ? <Image source={{ uri: perfil.avatar }} style={s.avatarImg} />
              : <Text style={s.avatarTxt}>{iniciais}</Text>
            }
          </View>
          <Text style={s.heroNome}>{perfil.nome}</Text>
          <View style={s.heroBadge}>
            <Ionicons name="medical" size={13} color="#4CAF50" />
            <Text style={s.heroBadgeTxt}>{perfil.especialidade}</Text>
          </View>
          {perfil.notaMedia !== null && (
            <View style={s.heroRating}>
              <Estrelas nota={Math.round(perfil.notaMedia)} />
              <Text style={s.heroRatingTxt}>{perfil.notaMedia.toFixed(1)} ({perfil.totalAvaliacoes} avaliações)</Text>
            </View>
          )}
        </View>

        {/* ── Stats ── */}
        <View style={s.statsRow}>
          <View style={s.statBox}>
            <Text style={s.statVal}>{anosExp ?? '—'}</Text>
            <Text style={s.statLbl}>Anos de{'\n'}Experiência</Text>
          </View>
          <View style={s.statDivider} />
          <View style={s.statBox}>
            <Text style={s.statVal}>{perfil.totalAgendamentos}</Text>
            <Text style={s.statLbl}>Consultas{'\n'}Realizadas</Text>
          </View>
          <View style={s.statDivider} />
          <View style={s.statBox}>
            <Text style={s.statVal}>{perfil.notaMedia?.toFixed(1) ?? '—'}</Text>
            <Text style={s.statLbl}>Nota{'\n'}Média</Text>
          </View>
        </View>

        {/* ── Sobre ── */}
        <View style={s.section}>
          <Text style={s.sectionTitle}>Sobre o Profissional</Text>
          <InfoRow icon="school-outline"   label="Formação"      value={anoFormacao ? `Formado em ${anoFormacao}` : 'Não informado'} />
          <InfoRow icon="ribbon-outline"   label="CRM"           value={perfil.crm} />
          <InfoRow icon="location-outline" label="Localização"   value={`${perfil.cidade}, ${perfil.estado}`} />
          <InfoRow icon="home-outline"     label="Endereço"      value={perfil.endereco} />
          <InfoRow icon="call-outline"     label="Telefone"      value={perfil.telefone ?? 'Não informado'} />
          <InfoRow icon="mail-outline"     label="E-mail"        value={perfil.email} />
        </View>

        {/* ── Avaliações recentes ── */}
        {perfil.avaliacoes.length > 0 && (
          <View style={s.section}>
            <Text style={s.sectionTitle}>Avaliações Recentes</Text>
            {perfil.avaliacoes.map(a => (
              <View key={a.id} style={s.avalCard}>
                <View style={s.avalHeader}>
                  <View style={s.avalAvatar}>
                    <Text style={s.avalAvatarTxt}>{a.paciente.charAt(0).toUpperCase()}</Text>
                  </View>
                  <View style={{ flex: 1, marginLeft: 10 }}>
                    <Text style={s.avalNome}>{a.paciente}</Text>
                    <Estrelas nota={a.nota} />
                  </View>
                  <Text style={s.avalData}>
                    {new Date(a.data).toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' })}
                  </Text>
                </View>
                {a.comentario ? <Text style={s.avalComentario}>"{a.comentario}"</Text> : null}
              </View>
            ))}
          </View>
        )}

        <View style={{ height: 100 }} />
      </ScrollView>

      {/* ── Botões fixos ── */}
      <View style={s.footerBtns}>
        <TouchableOpacity style={s.btnConversar} onPress={handleConversar} activeOpacity={0.8}>
          <Ionicons name="chatbubble-outline" size={18} color="#4CAF50" />
          <Text style={s.btnConversarTxt}>Conversar</Text>
        </TouchableOpacity>
        <TouchableOpacity style={s.btnAgendar} onPress={handleAgendar} activeOpacity={0.8}>
          <Ionicons name="calendar-outline" size={18} color="#FFF" />
          <Text style={s.btnAgendarTxt}>Agendar Consulta</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
};

const InfoRow: React.FC<{ icon: keyof typeof Ionicons.glyphMap; label: string; value: string }> = ({ icon, label, value }) => (
  <View style={s.infoRow}>
    <View style={s.infoIconBox}><Ionicons name={icon} size={18} color="#4CAF50" /></View>
    <View style={{ flex: 1 }}>
      <Text style={s.infoLabel}>{label}</Text>
      <Text style={s.infoValue}>{value}</Text>
    </View>
  </View>
);

const s = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#FAFAFA' },
  centered: { flex: 1, justifyContent: 'center', alignItems: 'center', gap: 12 },
  erroTxt: { fontSize: 15, color: '#AAA' },

  // Hero
  hero: { backgroundColor: '#FFF', alignItems: 'center', paddingVertical: 28, paddingHorizontal: 20, borderBottomWidth: 1, borderBottomColor: '#F0F0F0' },
  avatarCircle: { width: 90, height: 90, borderRadius: 45, backgroundColor: '#E8F5E9', alignItems: 'center', justifyContent: 'center', borderWidth: 3, borderColor: '#4CAF50', marginBottom: 14 },
  avatarImg: { width: 90, height: 90, borderRadius: 45 },
  avatarTxt: { fontSize: 32, fontWeight: '700', color: '#4CAF50' },
  heroNome: { fontSize: 22, fontWeight: '800', color: '#1A1A1A', textAlign: 'center' },
  heroBadge: { flexDirection: 'row', alignItems: 'center', gap: 5, backgroundColor: '#E8F5E9', paddingHorizontal: 12, paddingVertical: 5, borderRadius: 20, marginTop: 8 },
  heroBadgeTxt: { fontSize: 13, color: '#2E7D32', fontWeight: '700' },
  heroRating: { flexDirection: 'row', alignItems: 'center', gap: 8, marginTop: 10 },
  heroRatingTxt: { fontSize: 13, color: '#888' },

  // Stats
  statsRow: { flexDirection: 'row', backgroundColor: '#FFF', marginHorizontal: 16, marginTop: 16, borderRadius: 14, paddingVertical: 16, elevation: 2, shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.07, shadowRadius: 4, borderWidth: 1, borderColor: '#F0F0F0' },
  statBox: { flex: 1, alignItems: 'center', gap: 4 },
  statVal: { fontSize: 22, fontWeight: '800', color: '#4CAF50' },
  statLbl: { fontSize: 11, color: '#888', textAlign: 'center', lineHeight: 16 },
  statDivider: { width: 1, backgroundColor: '#F0F0F0' },

  // Seção
  section: { backgroundColor: '#FFF', marginHorizontal: 16, marginTop: 16, borderRadius: 14, padding: 16, elevation: 1, shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.05, shadowRadius: 3, borderWidth: 1, borderColor: '#F0F0F0' },
  sectionTitle: { fontSize: 16, fontWeight: '700', color: '#222', marginBottom: 14 },

  // InfoRow
  infoRow: { flexDirection: 'row', alignItems: 'center', paddingVertical: 10, borderBottomWidth: 1, borderBottomColor: '#F5F5F5' },
  infoIconBox: { width: 34, height: 34, borderRadius: 10, backgroundColor: '#E8F5E9', alignItems: 'center', justifyContent: 'center', marginRight: 12 },
  infoLabel: { fontSize: 11, color: '#AAA', fontWeight: '600', textTransform: 'uppercase' },
  infoValue: { fontSize: 14, color: '#333', fontWeight: '500', marginTop: 1 },

  // Avaliações
  avalCard: { backgroundColor: '#FAFAFA', borderRadius: 10, padding: 12, marginBottom: 10, borderWidth: 1, borderColor: '#F0F0F0' },
  avalHeader: { flexDirection: 'row', alignItems: 'center' },
  avalAvatar: { width: 36, height: 36, borderRadius: 18, backgroundColor: '#E8F5E9', alignItems: 'center', justifyContent: 'center' },
  avalAvatarTxt: { fontSize: 15, fontWeight: '700', color: '#4CAF50' },
  avalNome: { fontSize: 13, fontWeight: '700', color: '#333', marginBottom: 3 },
  avalData: { fontSize: 11, color: '#AAA' },
  avalComentario: { fontSize: 13, color: '#555', fontStyle: 'italic', marginTop: 8, lineHeight: 18 },

  // Footer
  footerBtns: { flexDirection: 'row', gap: 10, paddingHorizontal: 16, paddingVertical: 12, backgroundColor: '#FFF', borderTopWidth: 1, borderTopColor: '#EEE' },
  btnConversar: { flex: 1, flexDirection: 'row', alignItems: 'center', justifyContent: 'center', gap: 7, borderWidth: 1.5, borderColor: '#4CAF50', borderRadius: 12, paddingVertical: 13 },
  btnConversarTxt: { fontSize: 14, fontWeight: '700', color: '#4CAF50' },
  btnAgendar: { flex: 2, flexDirection: 'row', alignItems: 'center', justifyContent: 'center', gap: 7, backgroundColor: '#4CAF50', borderRadius: 12, paddingVertical: 13, elevation: 2 },
  btnAgendarTxt: { fontSize: 14, fontWeight: '700', color: '#FFF' },
});

export default MedicoDetalhesScreen;

import { Request, Response } from 'express';
import prisma from '../prisma/prismaClient';

class ClinicasController {
  async recomendadas(req: Request, res: Response) {
    try {
      const { estado, cidade } = req.query;

      const where: any = {
        tipo: 'clinica',
      };

      if (estado) where.estado = estado;
      if (cidade) where.cidade = cidade;

      // Busca usuários do tipo clinica que tenham nome e localização (simplificado)
      const clinicas = await prisma.usuario.findMany({
        where,
        select: {
          id: true,
          nome: true,
          email: true,
          cidade: true,
          estado: true,
          fotoPerfil: true, // Ou avatar se preferir padronizar
        },
        take: 10,
      });

      // Mapeia para o formato esperado pelo front
      const formatted = clinicas.map(c => ({
        id: c.id,
        nome: c.nome,
        avatar: c.fotoPerfil,
        localizacao: `${c.cidade}, ${c.estado}`,
        nota: 5.0, // Mock de nota por enquanto
      }));

      return res.json(formatted);
    } catch (error) {
      console.error('Erro ao buscar clínicas recomendadas:', error);
      return res.status(500).json({ error: 'Erro interno do servidor' });
    }
  }

  async listar(req: Request, res: Response) {
      // Implementação básica de listagem se necessário
      const clinicas = await prisma.usuario.findMany({ where: { tipo: 'clinica' } });
      return res.json(clinicas);
  }
}

export default new ClinicasController();

import { Request, Response } from 'express';
import prisma from '../prisma/prismaClient';

class ClinicasController {
  async recomendadas(req: Request, res: Response) {
    try {
      const { estado, cidade } = req.query;

      const where: any = {
        tipo: 'clinica',
        ativo: true,
      };

      if (estado) where.estado = estado;
      if (cidade) where.cidade = cidade;

      const clinicas = await prisma.usuario.findMany({
        where,
        select: {
          id: true,
          nome: true,
          email: true,
          cidade: true,
          estado: true,
          avatar: true,
        },
        take: 10,
        orderBy: { criado_em: 'desc' },
      });

      const formatted = clinicas.map(c => ({
        id: c.id,
        nome: c.nome,
        avatar: c.avatar ?? null,
        localizacao: c.cidade && c.estado ? `${c.cidade}, ${c.estado}` : c.cidade || c.estado || null,
        nota: 5.0,
      }));

      return res.json(formatted);
    } catch (error) {
      console.error('Erro ao buscar clínicas recomendadas:', error);
      return res.status(500).json({ error: 'Erro interno do servidor' });
    }
  }

  async listar(req: Request, res: Response) {
    try {
      const clinicas = await prisma.usuario.findMany({
        where: { tipo: 'clinica', ativo: true },
        select: {
          id: true,
          nome: true,
          email: true,
          cidade: true,
          estado: true,
          avatar: true,
          criado_em: true,
        },
        orderBy: { nome: 'asc' },
      });
      return res.json(clinicas);
    } catch (error) {
      console.error('Erro ao listar clínicas:', error);
      return res.status(500).json({ error: 'Erro interno do servidor' });
    }
  }
}

export default new ClinicasController();
